5	const { Pool } = pg;
6	
7	let pool: pg.Pool | null = null;
8	
9	export function getPool(): pg.Pool {
10	  if (!pool) {
11	    pool = new Pool({
12	      connectionString: config.databaseUrl,
13	      max: 20,
14	      idleTimeoutMillis: 30_000,
15	      connectionTimeoutMillis: 2_000,
16	    });
17	    pool.on('error', (err) => {
18	      logger.error({ err }, 'Unexpected idle pg client error');
19	    });
20	  }
21	  return pool;
22	}
23	
24	export async function query<T extends pg.QueryResultRow = pg.QueryResultRow>(
25	  text: string,
26	  params?: unknown[],
27	): Promise<pg.QueryResult<T>> {
28	  return getPool().query<T>(text, params);
29	}
30	
31	export async function queryOne<T extends pg.QueryResultRow = pg.QueryResultRow>(
32	  text: string,
33	  params?: unknown[],
34	): Promise<T | null> {
35	  const result = await query<T>(text, params);
36	  return result.rows[0] || null;
37	}
38	
39	export async function withTransaction<T>(fn: (client: pg.PoolClient) => Promise<T>): Promise<T> {
40	  const client = await getPool().connect();
41	  try {
42	    await client.query('BEGIN');
43	    const result = await fn(client);
44	    await client.query('COMMIT');
45	    return result;
46	  } catch (err) {
47	    await client.query('ROLLBACK');
48	    throw err;
49	  } finally {
50	    client.release();
51	  }
52	}
