54	const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
55	
56	export interface RLSContext {
57	  userId?: string | undefined;
58	  orgId?: string | undefined;
59	}
60	
61	export async function queryWithContext<T extends pg.QueryResultRow = pg.QueryResultRow>(
62	  text: string,
63	  params: unknown[],
64	  ctx: RLSContext,
65	): Promise<pg.QueryResult<T>> {
66	  if (ctx.userId !== undefined && !UUID_REGEX.test(ctx.userId)) {
67	    throw new Error(`Invalid userId format: ${ctx.userId}`);
68	  }
69	  if (ctx.orgId !== undefined && !UUID_REGEX.test(ctx.orgId)) {
70	    throw new Error(`Invalid orgId format: ${ctx.orgId}`);
71	  }
72	
73	  const client = await getPool().connect();
74	  try {
75	    if (ctx.userId !== undefined) {
76	      await client.query(`SET LOCAL app.current_user_id = '${ctx.userId}'`);
77	    }
78	    if (ctx.orgId !== undefined) {
